import{_ as a,H as i,f as e,i as t}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"30-Rust 性能优化与火焰图","description":"","frontmatter":{},"headers":[],"relativePath":"../rustLearning/30-Rust性能优化与火焰图.md","filePath":"../rustLearning/30-Rust性能优化与火焰图.md","lastUpdated":1778496697000}'),l={name:"../rustLearning/30-Rust性能优化与火焰图.md"};function n(o,s,p,r,h,d){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="_30-rust-性能优化与火焰图" tabindex="-1">30-Rust 性能优化与火焰图 <a class="header-anchor" href="#_30-rust-性能优化与火焰图" aria-label="Permalink to &quot;30-Rust 性能优化与火焰图&quot;">​</a></h1><blockquote><p>&quot;写出来的 Rust 代码已经够快了，但如果不小心用了太多的 <code>.clone()</code> 或者乱用锁，还是会拖慢程序。我们来看看如何科学地优化。&quot;</p></blockquote><p>不要盲目优化，优化前第一件事是：<strong>性能剖析（Profiling）</strong>。</p><h2 id="一、发布模式编译-release-profile" tabindex="-1">一、发布模式编译 (Release Profile) <a class="header-anchor" href="#一、发布模式编译-release-profile" aria-label="Permalink to &quot;一、发布模式编译 (Release Profile)&quot;">​</a></h2><p>在你开始抱怨 Rust 程序慢之前，请确认你是否加了 <code>--release</code>！</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release</span></span></code></pre></div><p>Debug 模式包含大量调试符号、未优化的计算，还会检查溢出。<strong>Release 模式下，速度通常有 10 到 100 倍的提升！</strong></p><p>你还可以通过配置 <code>Cargo.toml</code> 进一步压榨性能：</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">profile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">release</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">opt-level = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 最大优化（默认就是 3）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lto = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 开启 Link Time Optimization (链接时优化)，会显著变快但编译更慢</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codegen-units = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 牺牲并行编译时间，让 LLVM 更好地分析整个代码库并优化</span></span></code></pre></div><h2 id="二、定位瓶颈-生成火焰图-flamegraph" tabindex="-1">二、定位瓶颈：生成火焰图 (Flamegraph) <a class="header-anchor" href="#二、定位瓶颈-生成火焰图-flamegraph" aria-label="Permalink to &quot;二、定位瓶颈：生成火焰图 (Flamegraph)&quot;">​</a></h2><p>火焰图能直观地看出 CPU 的时间都花在了哪个函数上。</p><p>安装工具：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flamegraph</span></span></code></pre></div><p>运行项目并生成图表：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flamegraph</span></span></code></pre></div><p>跑完后，当前目录下会生成一个 <code>flamegraph.svg</code>，用浏览器打开。</p><ul><li><strong>宽度</strong>：代表占用 CPU 的时间长短。</li><li><strong>高度</strong>：代表函数调用栈。 <strong>找瓶颈的方法：找最顶层、最长的那块“平顶山”！那就是性能卡点。</strong></li></ul><h2 id="三、常见性能陷阱与优化套路" tabindex="-1">三、常见性能陷阱与优化套路 <a class="header-anchor" href="#三、常见性能陷阱与优化套路" aria-label="Permalink to &quot;三、常见性能陷阱与优化套路&quot;">​</a></h2><p>通过火焰图定位到问题函数后，常见的优化手段有：</p><ol><li><strong>滥用 <code>.clone()</code></strong>： <ul><li>症状：火焰图里出现大量的 <code>memcpy</code> 或内存分配。</li><li>解法：考虑改用引用（借用），或者如果字符串只读，改用 <code>Rc&lt;str&gt;</code> 或 <code>Arc&lt;str&gt;</code>。</li></ul></li><li><strong>频繁的小块内存分配</strong>： <ul><li>症状：火焰图里全是 <code>malloc</code> 和 <code>free</code>。比如在一个循环里不断地 <code>String::new()</code> 或 <code>Vec::new()</code>。</li><li>解法：在循环外使用 <code>String::with_capacity(size)</code> 预分配内存，循环内用 <code>.clear()</code> 重复利用。</li></ul></li><li><strong>锁的争用 (Lock Contention)</strong>： <ul><li>症状：多线程程序中，CPU 利用率上不去。</li><li>解法：缩小锁的临界区（只把必要的操作放进 <code>lock()</code> 里面，拿到数据赶紧 <code>drop</code> 锁）；或者改用 <code>RwLock</code>（读写锁）；实在不行改用无锁数据结构（如 <code>crossbeam</code> 的队列）或消息传递。</li></ul></li><li><strong>哈希碰撞和计算开销</strong>： <ul><li>Rust 默认的 <code>HashMap</code> 为了防范 DOS 攻击，用的是安全的 SipHash，速度相对较慢。</li><li>解法：如果你完全信任你的数据源，可以换成 <code>rustc-hash</code> 或 <code>ahash</code> 这种极致追求速度的哈希算法。</li></ul></li></ol><hr><h2 id="🎉-结语" tabindex="-1">🎉 结语 <a class="header-anchor" href="#🎉-结语" aria-label="Permalink to &quot;🎉 结语&quot;">​</a></h2><p>祝贺你！读到这里，你已经完成了整个 Rust 学习路线。 从所有权的折磨，到多线程的无畏，再到 Web 服务和底层优化。 接下来的路，只有通过<strong>不断写代码、读报错、改代码</strong>来前行了。</p><p><strong>愿编译期与你同在！</strong></p>`,24)])])}const k=a(l,[["render",n]]);export{g as __pageData,k as default};
